/**
 * @method 
 * @name f_RetrieveCntrInfo 
 * @description 검색조건 초기화
 */
scwin.f_RetrieveCntrInfo = async function () {
  let v_strRegNo = scwin.strRegNo;

  //그리드용 컨테이너 정보 조회
  if (acb_onReqCls.getValue() == "I" && v_strRegNo == "") {
    sbm_CntrSizInfo.action = "/cm.zz.RetrieveComboCMD.do" + "?sysCd=OnRequestEBC" + "&queryId=retrieveCntrSizInfo" + "&blNo=" + ed_blBkNo.getValue() + "&bookingNo=";
    await scwin.submitExcute(sbm_CntrSizInfo);
    scwin.gridItemSet('size', 'code', 'name', 'cntrSizCd');
    sbm_CntrTypInfo.action = "/cm.zz.RetrieveComboCMD.do" + "?sysCd=OnRequestEBC" + "&queryId=retrieveCntrTypInfo" + "&blNo=" + ed_blBkNo.getValue() + "&bookingNo=";
    await scwin.submitExcute(sbm_CntrTypInfo);
    scwin.gridItemSet('type', 'code', 'name', 'cntrTypCd');
    if (["WHL", "IAL", "OOCL"].includes(ed_lineCd.getValue())) {
      sbm_CntrSizInfo.action = "/cm.zz.RetrieveCodeCMD.do?grpCd=OP101";
      await scwin.submitExcute(sbm_CntrSizInfo);
      scwin.gridItemSet('size', 'cd', 'cdNm', 'cntrSizCd');
      sbm_CntrTypInfo.action = "/cm.zz.RetrieveCodeCMD.do?grpCd=OP102";
      await scwin.submitExcute(sbm_CntrTypInfo);
      scwin.gridItemSet('type', 'cd', 'cdNm', 'cntrTypCd');
    }
    ;
  } else if (acb_onReqCls.getValue() == "I" && v_strRegNo != "") {
    if (["WHL", "IAL", "OOCL"].includes(ed_lineCd.getValue())) {
      if (ed_lane.getValue() != "KSI") {
        sbm_CntrSizInfo.action = "/cm.zz.RetrieveCodeCMD.do?grpCd=OP101";
        await scwin.submitExcute(sbm_CntrSizInfo);
        scwin.gridItemSet('size', 'cd', 'cdNm', 'cntrSizCd');
        gr_goodsInfo.setColumnVisible("cntrNo", true);
        gr_goodsInfo.setColumnVisible("reqQty", false);
        scwin.gridMinNumUserData(false);
      } else {
        sbm_CntrSizInfo.action = "/cm.zz.RetrieveComboCMD.do?sysCd=OnRequestEBC&queryId=retrieveCntrSizInfo&blNo=" + ed_blBkNo.getValue() + "&bookingNo=";
        await scwin.submitExcute(sbm_CntrSizInfo);
        scwin.gridItemSet('size', 'code', 'name', 'cntrSizCd');
        sbm_CntrTypInfo.action = "/cm.zz.RetrieveComboCMD.do?sysCd=OnRequestEBC&queryId=retrieveCntrTypInfo&blNo=" + ed_blBkNo.getValue() + "&bookingNo=";
        await scwin.submitExcute(sbm_CntrTypInfo);
        scwin.gridItemSet('type', 'code', 'name', 'cntrTypCd');
        gr_goodsInfo.setColumnVisible("cntrNo", false);
        gr_goodsInfo.setColumnVisible("reqQty", true);
        scwin.gridMinNumUserData(true);
      }
      ;
    } else {
      sbm_CntrSizInfo.action = "/cm.zz.RetrieveCodeCMD.do?grpCd=OP101";
      await scwin.submitExcute(sbm_CntrSizInfo);
      scwin.gridItemSet('size', 'cd', 'cdNm', 'cntrSizCd');
      sbm_CntrTypInfo.action = "/cm.zz.RetrieveCodeCMD.do?grpCd=OP102";
      await scwin.submitExcute(sbm_CntrTypInfo);
      scwin.gridItemSet('type', 'cd', 'cdNm', 'cntrTypCd');
      gr_goodsInfo.setColumnVisible("cntrNo", false);
      gr_goodsInfo.setColumnVisible("reqQty", true);
      scwin.gridMinNumUserData(true);
    }
    ;
  } else if (acb_onReqCls.getValue() == "O" && v_strRegNo == "") {
    sbm_CntrSizInfo.action = "/cm.zz.RetrieveCodeCMD.do?grpCd=OP101";
    await scwin.submitExcute(sbm_CntrSizInfo);
    scwin.gridItemSet('size', 'cd', 'cdNm', 'cntrSizCd');
    sbm_CntrTypInfo.action = "/cm.zz.RetrieveCodeCMD.do?grpCd=OP102";
    await scwin.submitExcute(sbm_CntrTypInfo);
    scwin.gridItemSet('type', 'cd', 'cdNm', 'cntrTypCd');
  } else if (acb_onReqCls.getValue() == "O" && v_strRegNo != "") {
    gr_goodsInfo.setColumnVisible("cntrNo", false);
    gr_goodsInfo.setColumnVisible("reqQty", true);
    scwin.gridMinNumUserData(true);
    sbm_CntrSizInfo.action = "/cm.zz.RetrieveCodeCMD.do?grpCd=OP101";
    await scwin.submitExcute(sbm_CntrSizInfo);
    scwin.gridItemSet('size', 'cd', 'cdNm', 'cntrSizCd');
    sbm_CntrTypInfo.action = "/cm.zz.RetrieveCodeCMD.do?grpCd=OP102";
    await scwin.submitExcute(sbm_CntrTypInfo);
    scwin.gridItemSet('type', 'cd', 'cdNm', 'cntrTypCd');
  } else if (acb_onReqCls.getValue() == "O" && v_strRegNo == "") {
    if (["WHL", "IAL"].includes(ed_lineCd.getValue())) {
      if (ed_lane.getValue() != "KSI") {
        gr_goodsInfo.setColumnVisible("cntrNo", true);
        gr_goodsInfo.setColumnVisible("reqQty", false);
        scwin.gridMinNumUserData(false);
      } else {
        gr_goodsInfo.setColumnVisible("cntrNo", false);
        gr_goodsInfo.setColumnVisible("reqQty", true);
        scwin.gridMinNumUserData(true);
      }
    } else {
      gr_goodsInfo.setColumnVisible("cntrNo", false);
      gr_goodsInfo.setColumnVisible("reqQty", true);
      scwin.gridMinNumUserData(true);
    }
    ;
  }
  ;
  return true;
};

/**
 * @method 
 * @name gridItemSet 
 * @description 그리드 select 컴포넌트 아이템 세팅
 */
scwin.gridItemSet = function (type, value, label, columnId) {
  let dltObj, targetDlt;
  switch (type) {
    case 'size':
      dltObj = ds_CntrSizInfo;
      targetDlt = ds_size_item;
      break;
    case 'type':
      dltObj = ds_CntrTypInfo;
      targetDlt = ds_type_item;
      break;
    default:
      return;
  }
  ;
  let allData = dltObj.getAllJSON();
  let insertItem = [];
  for (let i = 0; i < allData.length; i++) {
    let rowData = allData[i];
    insertItem.push({
      code: rowData[value],
      name: rowData[label]
    });
  }
  ;
  targetDlt.setJSON(insertItem, false);
};

