/**
 * @event 
 * @name submitPre 
 * @description submit 요청전
 */
scwin.submitPre = function (e) {
  let submitObj = $p.getComponentById(e.id);
  switch (submitObj) {
    case sbm_saveOnRequestInfo:
      const rowData = dma_onRequestInfo.getJSON();
      const overwrite = ds_onRequestInfo.getRowCount() > 0;

      // const blBkNoKey = acb_onReqCls.getValue() == 'I' ? 'blNo' : 'bookingNo'
      // dma_onRequestInfo.set(blBkNoKey, ed_blBkNo.getValue());

      ds_onRequestInfo.setRowJSON(0, rowData, overwrite);
      break;
    case sbm_retrieveOnRequestInfo:
      let jsonData = dma_retrieveCondition.getJSON();
      jsonData["selfTransClntNo"] = ed_srchSelfTransClntNo.getValue();
      jsonData["onReqNo"] = ed_onReqNo.getValue();
      jsonData["impExpClsCd"] = acb_srchImpExpCls.getValue();
      dma_retrieveCondition.setJSON(jsonData);
      break;
    default:
      break;
  }
};

/**
 * @event 
 * @name submitdone 
 * @description submit 정상
 */
scwin.submitdone = async function (e) {
  let submitObj = $p.getComponentById(e.id);

  // OnFail
  if (e.responseJSON.resultDataSet[0].Code == -1) return;
  switch (submitObj) {
    case sbm_saveOnRequestInfo:
      // success
      await $c.gus.cfAlertMsg($p, MSG_CM_INF_001); // 성공적으로 저장하였습니다

      // disable 처리
      $c.gus.cfDisableKeyData($p);
      gr_goodsInfo.setGridReadOnly(true);
      $c.gus.cfDisableBtn($p, [btn_Upt]);
      $c.gus.cfDisableBtn($p, [btn_Upt, udc_gridBottom]);
      $c.gus.cfDisableObjects($p, [img_selfTransClntNo, ica_closingTime, btn_reqClntNo, btn_bilgClntNo, btn_realMchtClntNo, btn_middleClntNo, img_doorRgnCd, ica_onIntendDd]);
      switch (scwin.actDiv) {
        case "I":
          //신규등록인 경우 등록시 입력한 자가운송사, 수출입구분, 현재일자로 refresh
          dma_retrieveCondition.set('selfTransClntNo', ed_selfTransClntNo.getValue());
          dma_retrieveCondition.set('onReqNo', ds_onReqNoTemp.getCellData(0, "onReqNo"));
          acb_srchImpExpCls.setValue(acb_onReqCls.getValue());
          await scwin.submitExcute(sbm_retrieveOnRequestInfo);
          scwin.actDiv = "R";
          break;
        case "D":
          //삭제인 경우 상단 조회조건으로 refresh
          ed_onReqNo.setValue(ed_onReqNo.getValue());
          scwin.f_Retrieve('');
          break;
        default:
          break;
      }
      ;
      break;
    case sbm_retrieveOnRequestGoodsLimitInfo:
      // success
      let focusedIdx = ds_onReqGoodsInfo.getRowPosition();
      if (ds_onReqGoodsLimitInfo.getRowCount() == 0) {
        let targetStr = '';
        switch (acb_onReqCls.getValue()) {
          case 'I':
            targetStr = 'BL';
            break;
          case 'O':
            targetStr = '오더';
            break;
          default:
            break;
        }
        ;
        if (!["WHL", "IAL", "OOCL"].includes(ed_lineCd.getValue())) {
          await $c.gus.cfAlertMsg($p, targetStr + "에 등록된 컨테이너 규격이 아닙니다.");
        }
        ;
        scwin.addFlag = false;
        gr_goodsInfo.setFocusedCell(focusedIdx, 'cntrSizCd');
        return;
      }
      ;
      scwin.addFlag = true;

      //한도 체크후 품목코드를 상차요청품목 dataset에 넣어둔다.
      let limitFocuedIdx = ds_onReqGoodsLimitInfo.getRowPosition();
      let limitCommCd = ds_onReqGoodsLimitInfo.getCellData(limitFocuedIdx, "commCd");
      ds_onReqGoodsInfo.setCellData(focusedIdx, "commCd", limitCommCd);
      break;
    case sbm_retrieveOnRequestInfo:
      // success
      ds_onRequestInfo.setRowPosition(0);
      ds_onReqGoodsInfo.setRowPosition(0);
      ds_onReqErrInfo.setRowPosition(0);
      let rowData = ds_onRequestInfo.getRowJSON(0);
      dma_onRequestInfo.setJSON(rowData);
      let v_lineCd = ds_onRequestInfo.getCellData(0, "lineCd");
      let v_impExpClsCd = ds_onRequestInfo.getCellData(0, "impExpClsCd");
      if (ds_onRequestInfo.getCellData(ds_onRequestInfo.getRowPosition(), "onReqNo") == '') {
        await $c.gus.cfAlertMsg($p, MSG_CM_WRN_002);
        ed_onReqNo_num.setValue("");
        ds_onReqGoodsInfo.removeAll();
      }
      ;
      $c.gus.cfDisableKeyData($p);
      gr_goodsInfo.setGridReadOnly(true);
      if (scwin.strRegNo == "") {
        $c.gus.cfDisableObjects($p, [img_selfTransClntNo, img_srchLineCd, ica_closingTime, btn_reqClntNo, btn_bilgClntNo, btn_realMchtClntNo, img_doorRgnCd, ica_onIntendDd]);
        if (v_lineCd == "WJS" && v_impExpClsCd == "O") {
          scwin.cf_ShowObject([title_vanTerm, span_vanTerm]);
          scwin.cf_HideObject([title_vanTerm, span_vanTerm]);
          acb_jeVanTermCd.setValue(ds_onRequestInfo.getCellData(0, "jeVanTerm"));
        } else if (["EVER", "HTML", "EMS", "ITS"].includes(v_lineCd) && v_impExpClsCd == "O") {
          scwin.cf_ShowObject([title_masterKey, span_masterKey]);
          scwin.cf_HideObject([title_vanTerm, span_vanTerm]);
        } else {
          scwin.cf_HideObject([title_vanTerm, span_vanTerm, title_masterKey, span_masterKey]);
        }
        ;
      } else {
        $c.gus.cfDisableObjects($p, [img_selfTransClntNo, img_srchLineCd, ica_closingTime, btn_reqClntNo, btn_bilgClntNo, btn_realMchtClntNo, img_doorRgnCd, ica_onIntendDd, btn_lane]);
        if (v_lineCd == "WJS" && v_impExpClsCd == "O") {
          scwin.cf_ShowObject([title_vanTerm, span_vanTerm]);
          scwin.cf_HideObject([title_vanTerm, span_vanTerm]);
          acb_jeVanTermCd.setValue(ds_onRequestInfo.getCellData(0, "jeVanTerm"));
        } else if (["EVER", "HTML", "EMS", "ITS"].includes(v_lineCd) && v_impExpClsCd == "O") {
          scwin.cf_ShowObject([title_masterKey, span_masterKey]);
          scwin.cf_HideObject([title_vanTerm, span_vanTerm]);
        } else {
          scwin.cf_HideObject([title_vanTerm, span_vanTerm, title_masterKey, span_masterKey]);
        }
        ;
      }
      ;

      //검색용 히든 초기화
      hid_srchSelfTransClntNo.setValue("");
      hid_srchSelfTransClntNm.setValue("");
      hid_lineCd.setValue("");
      hid_lineNm.setValue("");
      hid_selfTransClntNo.setValue("");
      hid_selfTransClntNm.setValue("");
      hid_reqClntNo.setValue("");
      hid_bilgClntNo.setValue("");
      hid_realMchtClntNo.setValue("");
      hid_doorRgnCd.setValue("");
      hid_odrNo.setValue("");

      //그리드 콤보박스용 컨테이너 정보 조회
      await scwin.f_RetrieveCntrInfo();

      //조회된 데이터가 있을경우만 메시지 띄우도록 수정 20161025 SITC 로지 요청
      if (ds_onRequestInfo.getRowCount() > 0) {
        if (ds_onRequestInfo.getCellData(0, "serCd") != "0" && ds_onRequestInfo.getCellData(0, "admitClsCd") != 'O') {
          $c.win.alert($p, " SITC LOGI 승인분입니다.\n" + " 담당자 : 이지훈  TEL 466-3397  FAX 466-3327\n" + " 주소 : 부산시 중구 중앙동 4가 79-9 한진해운빌딩 18층");
        }
        ;
      }
      ;
      await scwin.ds_onRequestInfo_OnLoadCompleted();
      await scwin.ds_onReqGoodsInfo_onFilter();
      scwin.ds_onReqErrInfo_OnLoadCompleted();
      break;
    case sbm_retrieveAdmitClsCdInfo:
      scwin.ds_admitClsCdInfo_OnLoadCompleted();
      break;
    case sbm_custCoInfo:
      if (ds_custCoInfo.getRowCount() > 0) {
        const obj1 = $p.getComponentById(scwin.objArray[1]);
        const obj2 = $p.getComponentById(scwin.objArray[2]);
        const obj3 = $p.getComponentById(scwin.objArray[3]);
        const obj4 = $p.getComponentById(scwin.objArray[4]);
        const obj5 = $p.getComponentById(scwin.objArray[5]);
        const obj6 = $p.getComponentById(scwin.objArray[6]);
        let rowData = ds_custCoInfo.getRowJSON(0);
        if (scwin.objArray[0] == 2) {
          obj1.setValue(rowData['clntNo']);
          obj2.setValue(rowData['clntNo']);
          obj3.setValue(rowData['clntNm']);
          obj4.setValue(rowData['coTelNo']);
          obj5.setValue(rowData['mpTelNo']);
          obj6.setValue(rowData['pic']);
        } else if (scwin.objArray[0] > 2) {
          obj1.setValue(rowData['clntNo']);
          obj2.setValue(rowData['clntNo']);
          obj3.setValue(rowData['clntNm']);
          obj4.setValue(rowData['busiNo']);
          obj5.setValue(rowData['pic']);
          obj6.setValue(rowData['mpTelNo']);
        }
        ;
      }
      ;
      break;
    case sbm_blBkInfo:
      let v_strRegNo = scwin.strRegNo;
      if (ds_blBkInfo.getRowCount() < 1) {
        if (acb_onReqCls.getValue() == "I" && v_strRegNo != "") {
          //수출일때는 생략(20060311)
          if (["WHL", "IAL"].includes(ed_lineCd.getValue())) {
            if (ed_lane.getValue() == "KSI") {
              let msg = "1. BL 번호를 올바르게 입력하였는지 확인하세요.\n\n" + "2. BL 번호가 올바르게 입력되었음에도 동일한 메시지가 출력된다면," + " 동부부산의 각라인 파트담당자에게,\n" + "적하목록의 수신여부를 확인하세요.\n\n" + "(적하목록을 수신받지 않아도 위와 같은 메시지가 발생합니다. 이는 세관신고와는\n" + "별도로 통합물류시스템의 적하목록 수신을 말합니다.)";
              await $c.gus.cfAlertMsg($p, msg);
              ed_blBkNo.focus();
              return;
            }
            ;
          }
          ;
        } else if (acb_onReqCls.getValue() == "I") {
          let msg = "1. BL 번호를 올바르게 입력하였는지 확인하세요.\n\n" + "2. BL 번호가 올바르게 입력되었음에도 동일한 메시지가 출력된다면," + " 동부부산의 각라인 파트담당자에게,\n" + "적하목록의 수신여부를 확인하세요.\n\n" + "(적하목록을 수신받지 않아도 위와 같은 메시지가 발생합니다. 이는 세관신고와는\n" + "별도로 통합물류시스템의 적하목록 수신을 말합니다.)";
          await $c.gus.cfAlertMsg($p, msg);
          ed_blBkNo.focus();
          return;
        }
        ;
      } else {
        if (v_strRegNo == "") {
          const retData = ds_blBkInfo.getRowJSON(0);
          ed_lineCd.setValue(retData["lineCd"]);
          txt_lineNm.setValue(retData["lineNm"]);

          // 동작 달라 추가
          ed_vsslNm.setValue(retData["vsslNm"].slice(0, 4));
          ed_portcnt.setValue(retData["portcnt"]);
        }
        ;
      }
      ;
      break;
    case sbm_pickuprgnCd:
      acb_pickuprgnCd.setSelectedIndex(0);
      if (scwin.strRegNo != "") {
        acb_pickuprgnCd.setValue("PUS");
        $c.gus.cfDisableObjects($p, [acb_pickuprgnCd]);
      }
      ;
      break;
    default:
      break;
  }
  ;
};

/**
 * @method 
 * @name ds_onRequestInfo_OnLoadCompleted 
 * @description 조회 TR
 */
scwin.ds_onRequestInfo_OnLoadCompleted = async function () {
  let rowcnt = ds_onRequestInfo.getRowCount();
  let rowData;
  if (rowcnt == 0) return;
  if (ed_onReqNo.getValue() == "") {
    ed_onReqNo.setValue(ds_onRequestInfo.getCellData(0, "onReqNo"));
  }
  ;
  let vCBData = ds_onRequestInfo.getCellData(0, "onReqNo");
  ed_onReqNo_num.setValue(vCBData);
  ed_onReqNo_num.setValue(ed_onReqNo.getValue());
  rowData = ds_onRequestInfo.getRowJSON(0);
  if (["", "0"].includes(rowData["cbx_completeFlag"])) {
    cbx_completeFlag.setValue(0);
  } else {
    cbx_completeFlag.setValue(1);
  }
  ;

  //의왕인경우만 포워드관련항목이 필수입력 나머지지역의 경우는 선택
  if (acb_pickuprgnCd.getValue() == "EWY") {
    scwin.f_mandatoryInit(true);
  } else {
    scwin.f_mandatoryInit(false);
  }
  ;

  // pickup지역이 의왕인경우에는 수정버튼 invisible
  // TODO - asis에서 btn_Del이 enable 되는 경우가 없음, 실제로는 enable 되어 btn_Del 추가
  if (ds_onRequestInfo.getCellData(0, "pickuprgnCd") == 'EWY') {
    $c.gus.cfDisableBtn($p, [btn_Add, btn_Del]);
  } else {
    $c.gus.cfEnable($p, [btn_Add, btn_Del], true);
  }
  ;

  //pcy
  ed_vsslNm.setValue(ds_onRequestInfo.getCellData(0, "vsslCd"));
};

