      "middleClntNo": ed_middleClntNo.getValue(),
      "middleClntNm": middleClntNm.getValue(),
      "middleCrn": ed_middleCrn.getValue(),
      "middleClntPic": ed_middleEmpNm.getValue(),
      "middleClntCntctPl": ed_middleTelNo.getValue(),
      "doorNm": ed_doorNm.getValue(),
      "doorRgnCd": ed_doorRgnCd.getValue(),
      "doorRgnNm": txt_doorRgnNm.getValue(),
