/**
 * @event 
 * @name udc_lineCd_onblurCodeEvent (OnKillFocus)
 * @description Line 코드 code 포커스를 잃었을 때 발생한다.
 */
scwin.udc_lineCd_onblurCodeEvent = function (e) {
  if (ed_lineCd.getValue() == "") {
    scwin.cf_HideObject([title_vanTerm, span_vanTerm, title_masterKey, span_masterKey]);
    txt_lineNm.setValue("");
    return;
  } else if (ed_lineCd.getValue() == hid_lineCd.getValue()) {
    txt_lineNm.setValue(hid_lineNm.getValue());
    return;
  }
  ;
  if (ed_lineCd.getValue() == "PAN") {
    $c.win.alert($p, "2/27 부터 DEBIS 전산에서 코피노 전송요망\n 변원석씨 문의 T: 051-630-3663");
    scwin.cf_HideObject([title_vanTerm, span_vanTerm]);
  } else if (acb_onReqCls.getValue() == "O" && ["WJS", "wjs"].includes(ed_lineCd.getValue())) {
    scwin.cf_ShowObject([title_vanTerm, span_vanTerm]);
    scwin.cf_HideObject([title_masterKey, span_masterKey]);
  } else if (acb_onReqCls.getValue() == "O" && ["EVER", "HTML", "EMS", "ITS"].includes(ed_lineCd.getValue())) {
    scwin.cf_ShowObject([title_masterKey, span_masterKey]);
    scwin.cf_HideObject([title_vanTerm, span_vanTerm]);
  } else {
    scwin.cf_HideObject([title_vanTerm, span_vanTerm, title_masterKey, span_masterKey]);
  }
  ;
  scwin.f_Line_OpenPopup('retrieveLineInfo', ['ed_lineCd', 'txt_lineNm', 'hid_lineCd', 'hid_lineNm'], ed_lineCd.getValue(), '', 'T', ',,,');
};

